"use client";

import React from "react";
import { 
  FaBuilding, 
  FaHotel, 
  FaIndustry, 
  FaTools, 
  FaRecycle, 
  FaTruck, 
  FaWarehouse, 
  FaCogs 
} from "react-icons/fa";

const items = [
  { icon: FaBuilding, text: "Corporate Office Scrap Buyer" },
  { icon: FaHotel, text: "Hotel Scrap Buyer" },
  { icon: FaIndustry, text: "Organizational Scrap Buyer" },
  { icon: FaTools, text: "Corporate Office Dismantling" },
  { icon: FaRecycle, text: "E-Waste Recycling" },
  { icon: FaTruck, text: "Office Shifting" },
  { icon: FaWarehouse, text: "Warehouse Scrap" },
  { icon: FaCogs, text: "Metal Scrap" },
];

const Marquee = () => {
  return (
    <div className="w-full h-[40px] overflow-hidden bg-bg-light-green flex items-center -mt-[41px] relative z-20">
      <div className="flex whitespace-nowrap animate-marquee">
        {/* Render items twice to ensure seamless looping */}
        {[...items, ...items, ...items].map((item, index) => (
          <p key={index} className="inline-flex items-center text-wheat mx-5 leading-[40px]">
            <item.icon className="mr-2" /> {item.text}
          </p>
        ))}
      </div>
    </div>
  );
};

export default Marquee;
